function Item({ id, name, details }) {
  const [data, setData] = React.useState({ id, name, details });
  const [list, setList] = React.useState([]);

  React.useMemo(() => {
    if (data.id !== list[data.id].id) {
      setList([...list, data]);
    }
  }, [data, list]);

  return (
    <div>
      <h2>{name}</h2>
      <p>Price: {details.price}</p>
      <p>Description: {details.description}</p>
    </div>
  );
}

function App() {
  const [data, setData] = React.useState({ data: [] });

  React.useMemo(() => {
    setData({ data: [{ id: 1, name: "Item 1", details: { price: 10.99, description: "This is item 1" } }, { id: 2, name: "Item 2", details: { price: 5.99, description: "This is item 2" } }] });
  }, []);

  return (
    <div>
      {data.data.map((item, index) => (
        <Item key={index} id={item.id} name={item.name} details={item.details} />
      ))}
    </div>
  );
}

